#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int longestCommonSubsequence(string X, string Y) {
        int m = X.size(), n = Y.size();
        vector<vector<int>> dp(m + 1, vector<int>(n + 1, 0));
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (X[i - 1] == Y[j - 1]) {
                    dp[i][j] = dp[i - 1][j - 1] + 1;
                } else {
                    dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
                }
            }
        }
        return dp[m][n];
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    int m;
    if (!(cin >> m)) return 0;
    string X;
    if (!(cin >> X)) return 0;
    if (!(cin >> n)) return 0;
    string Y;
    if (!(cin >> Y)) return 0;
    Solution sol;
    int ans = sol.longestCommonSubsequence(X, Y);
    cout << ans << "\n";
    return 0;
}
